1	/**
2	 * GreenLeaf Service Worker — offline Knowledge Base + operational data cache
3	 *
4	 * Security: caches are scoped per user ID.  On logout all caches are wiped so
5	 * a subsequent user on the same workstation cannot access stale protected data.
6	 *
7	 * Offline strategy
8	 * ─────────────────
9	 * KB articles (/api/articles, /api/plant-care):
10	 *   Network-first → cache on success → serve from cache on error → 503 if no cache.
11	 *
12	 * Operational reads (/api/procurement, /purchase-orders, /receiving, /returns, /suppliers):
13	 *   Same network-first + cache strategy.
14	 *
15	 * Operational mutations (POST/PATCH/PUT/DELETE to procurement, purchase-orders,
16	 *   receiving, returns):
17	 *   Try network.  If offline, persist the request in IndexedDB and return 202
18	 *   with X-Offline-Queued:true.  On the next online event the SW replays the
19	 *   queue and notifies all open clients via postMessage {type:'QUEUE_REPLAYED'}.
20	 */
21	
22	const CACHE_VERSION = 'v2';
23	const ARTICLE_API_PATTERN = /\/api\/(articles|plant-care)/;
24	const OPERATIONAL_GET_PATTERN = /\/api\/(procurement|purchase-orders|receiving|returns|suppliers)/;
25	const OPERATIONAL_MUTATE_PATTERN = /\/api\/(procurement|purchase-orders|receiving|returns)/;
26	
27	// IndexedDB offline-operation queue
28	const IDB_NAME = 'greenleaf-offline-queue';
29	const IDB_VERSION = 1;
30	const IDB_STORE = 'operations';
31	
32	let activeUserId = null;
33	
34	function userKbCacheName() {
35	  return activeUserId ? `greenleaf-kb-${CACHE_VERSION}-${activeUserId}` : null;
36	}
37	
38	function userOpCacheName() {
39	  return activeUserId ? `greenleaf-ops-${CACHE_VERSION}-${activeUserId}` : null;
40	}
41	
42	// ── IndexedDB helpers ────────────────────────────────────────────────────────
43	
44	function openIDB() {
45	  return new Promise((resolve, reject) => {
46	    const req = indexedDB.open(IDB_NAME, IDB_VERSION);
47	    req.onupgradeneeded = (e) => {
48	      const db = e.target.result;
49	      if (!db.objectStoreNames.contains(IDB_STORE)) {
50	        db.createObjectStore(IDB_STORE, { keyPath: 'id', autoIncrement: true });
51	      }
52	    };
53	    req.onsuccess = (e) => resolve(e.target.result);
54	    req.onerror = () => reject(req.error);
55	  });
56	}
57	
58	async function enqueueOperation(request) {
59	  const body = await request.clone().text().catch(() => '');
60	  const db = await openIDB();
61	  return new Promise((resolve, reject) => {
62	    const tx = db.transaction(IDB_STORE, 'readwrite');
63	    const store = tx.objectStore(IDB_STORE);
64	    const record = {
65	      url: request.url,
66	      method: request.method,
67	      headers: Object.fromEntries(request.headers.entries()),
68	      body: body || undefined,
69	      userId: activeUserId,
70	      queuedAt: Date.now(),
71	    };
72	    const req = store.add(record);
73	    req.onsuccess = () => resolve(req.result);
74	    req.onerror = () => reject(req.error);
75	  });
76	}
77	
78	async function getPendingOperations() {
79	  const db = await openIDB();
80	  return new Promise((resolve, reject) => {
81	    const tx = db.transaction(IDB_STORE, 'readonly');
82	    const req = tx.objectStore(IDB_STORE).getAll();
83	    req.onsuccess = () =>
84	      resolve(
85	        (req.result || []).filter((op) => !activeUserId || op.userId === activeUserId),
86	      );
87	    req.onerror = () => reject(req.error);
88	  });
89	}
90	
91	async function removeOperation(id) {
92	  const db = await openIDB();
93	  return new Promise((resolve, reject) => {
94	    const tx = db.transaction(IDB_STORE, 'readwrite');
95	    const req = tx.objectStore(IDB_STORE).delete(id);
96	    req.onsuccess = () => resolve();
97	    req.onerror = () => reject(req.error);
98	  });
99	}
100	
101	async function replayQueue() {
102	  const ops = await getPendingOperations();
103	  if (!ops.length) return;
104	
105	  const results = [];
106	  for (const op of ops) {
107	    try {
108	      const init = {
109	        method: op.method,
110	        headers: op.headers,
111	      };
112	      if (op.body && op.method !== 'GET' && op.method !== 'HEAD') {
113	        init.body = op.body;
114	      }
115	      const response = await fetch(op.url, init);
116	      // Remove from queue on any non-5xx response (including 4xx client errors
117	      // that won't benefit from retrying).
118	      if (response.status < 500) {
119	        await removeOperation(op.id);
120	      }
121	      results.push({ id: op.id, status: response.status, success: response.ok });
122	    } catch {
123	      // Still offline — leave in queue
124	      results.push({ id: op.id, success: false, error: 'network' });
125	    }
126	  }
127	
128	  const clients = await self.clients.matchAll({ type: 'window' });
129	  for (const client of clients) {
130	    client.postMessage({ type: 'QUEUE_REPLAYED', results });
131	  }
132	}
133	
134	// ── Cache strategies ─────────────────────────────────────────────────────────
135	
136	async function networkFirst(request, cacheName) {
137	  if (!cacheName) {
138	    return fetch(request);
139	  }
140	
141	  const cache = await caches.open(cacheName);
142	  try {
143	    const response = await fetch(request);
144	    if (response.ok) {
145	      cache.put(request, response.clone());
146	    }
147	    return response;
148	  } catch {
149	    const cached = await cache.match(request);
150	    if (cached) return cached;
151	    return new Response(
152	      JSON.stringify({ error: 'Offline and no cached data available' }),
153	      {
154	        status: 503,
155	        headers: { 'Content-Type': 'application/json' },
156	      },
157	    );
158	  }
159	}
160	
161	async function mutationWithOfflineQueue(request) {
162	  try {
163	    return await fetch(request);
164	  } catch {
165	    const queueId = await enqueueOperation(request);
166	    return new Response(
167	      JSON.stringify({
168	        queued: true,
169	        queueId,
170	        message:
171	          'You are offline. This operation will be submitted automatically when connectivity is restored.',
172	      }),
173	      {
174	        status: 202,
175	        headers: {
176	          'Content-Type': 'application/json',
177	          'X-Offline-Queued': 'true',
178	        },
179	      },
180	    );
181	  }
182	}
183	
184	async function clearAllCaches() {
185	  const keys = await caches.keys();
186	  await Promise.all(keys.map((k) => caches.delete(k)));
187	  activeUserId = null;
188	}
189	
190	// ── Message handling ────────────────────────────────────────────────────────
191	
192	self.addEventListener('message', (event) => {
193	  const { type, userId } = event.data || {};
194	
195	  if (type === 'SET_USER') {
196	    activeUserId = userId || null;
197	  }
198	
199	  if (type === 'CLEAR_CACHE') {
200	    clearAllCaches().catch(() => {});
201	    if (event.ports && event.ports[0]) {
202	      event.ports[0].postMessage({ cleared: true });
203	    }
204	  }
205	
206	  if (type === 'SYNC_QUEUE') {
207	    replayQueue().catch(() => {});
208	  }
209	});
210	
211	// ── Online detection → trigger queue replay ──────────────────────────────────
212	
213	self.addEventListener('online', () => {
214	  replayQueue().catch(() => {});
215	});
216	
217	// ── Fetch interception ──────────────────────────────────────────────────────
218	
219	self.addEventListener('fetch', (event) => {
220	  const { request } = event;
221	  const url = request.url;
222	  const method = request.method;
223	
224	  if (ARTICLE_API_PATTERN.test(url)) {
225	    event.respondWith(networkFirst(request, userKbCacheName()));
226	    return;
227	  }
228	
229	  if (OPERATIONAL_GET_PATTERN.test(url) && method === 'GET') {
230	    event.respondWith(networkFirst(request, userOpCacheName()));
231	    return;
232	  }
233	
234	  if (
235	    OPERATIONAL_MUTATE_PATTERN.test(url) &&
236	    ['POST', 'PATCH', 'PUT', 'DELETE'].includes(method)
237	  ) {
238	    event.respondWith(mutationWithOfflineQueue(request));
239	  }
240	});
241	
242	// ── Activation: remove stale (version-bumped) caches ───────────────────────
243	
244	self.addEventListener('activate', (event) => {
245	  const validPrefixes = [
246	    `greenleaf-kb-${CACHE_VERSION}-`,
247	    `greenleaf-ops-${CACHE_VERSION}-`,
248	  ];
249	  event.waitUntil(
250	    caches.keys().then((keys) =>
251	      Promise.all(
252	        keys
253	          .filter((k) => !validPrefixes.some((p) => k.startsWith(p)))
254	          .map((k) => caches.delete(k)),
255	      ),
256	    ),
257	  );
258	});
259	
