3	/**
4	 * Tests for the offline mutation queue added to public/sw.js.
5	 *
6	 * Because a real Service Worker cannot run in a Vitest/Node environment,
7	 * we re-implement the SW queue helpers in a testable module-level form —
8	 * the same pattern used in sw-cache.test.ts for the cache helpers.
9	 *
10	 * Covers:
11	 *   - Mutations succeed immediately when online (fetch resolves)
12	 *   - Offline mutations are queued and 202 Queued is returned
13	 *   - Queued operations are replayed successfully on reconnect
14	 *   - 5xx responses are NOT removed from the queue (retry later)
15	 *   - Non-5xx client errors (4xx) ARE removed from the queue (won't fix itself)
16	 *   - Queue is user-scoped: a different user's operations are not replayed
17	 *   - Operational GETs use network-first with ops-scoped cache key
18	 *   - Cache cleanup on logout removes both kb and ops caches
19	 */
20	
21	// ── Re-implement the SW queue helpers in a testable form ──────────────────────
22	
23	const CACHE_VERSION = 'v2';
24	
25	interface QueuedOp {
26	  id: number;
27	  url: string;
28	  method: string;
29	  headers: Record<string, string>;
30	  body?: string;
31	  userId: string | null;
32	  queuedAt: number;
33	}
34	
35	function makeSwScope() {
36	  let activeUserId: string | null = null;
37	  let nextId = 1;
38	  const queue: QueuedOp[] = [];
39	  const storedCaches: Record<string, Map<string, Response>> = {};
40	
41	  // ── Cache helpers ──────────────────────────────────────────────────────────
42	
43	  const cacheApi = {
44	    open: vi.fn(async (name: string) => {
45	      if (!storedCaches[name]) storedCaches[name] = new Map();
46	      return {
47	        put: vi.fn((req: Request, res: Response) => {
48	          storedCaches[name].set(req.url, res);
49	        }),
50	        match: vi.fn(async (req: Request) => storedCaches[name].get(req.url) ?? undefined),
51	      };
52	    }),
53	    keys: vi.fn(async () => Object.keys(storedCaches)),
54	    delete: vi.fn(async (name: string) => {
55	      delete storedCaches[name];
56	      return true;
57	    }),
58	  };
59	
60	  function userKbCacheName() {
61	    return activeUserId ? `greenleaf-kb-${CACHE_VERSION}-${activeUserId}` : null;
62	  }
63	
64	  function userOpCacheName() {
65	    return activeUserId ? `greenleaf-ops-${CACHE_VERSION}-${activeUserId}` : null;
66	  }
67	
68	  async function networkFirst(req: Request, fetchImpl: typeof fetch, forOps = false) {
69	    const cacheName = forOps ? userOpCacheName() : userKbCacheName();
70	    if (!cacheName) return fetchImpl(req);
71	    const cache = await cacheApi.open(cacheName);
72	    try {
73	      const response = await fetchImpl(req);
74	      if ((response as Response).ok) cache.put(req, (response as Response).clone());
75	      return response;
76	    } catch {
77	      const cached = await cache.match(req);
78	      return (
79	        cached ??
80	        new Response(JSON.stringify({ error: 'Offline and no cached data available' }), {
81	          status: 503,
82	          headers: { 'Content-Type': 'application/json' },
83	        })
84	      );
85	    }
86	  }
87	
88	  // ── Queue helpers ──────────────────────────────────────────────────────────
89	
90	  async function enqueueOperation(req: Request): Promise<number> {
91	    const body = await req.clone().text().catch(() => '');
92	    const record: QueuedOp = {
93	      id: nextId++,
94	      url: req.url,
95	      method: req.method,
96	      headers: Object.fromEntries(req.headers.entries()),
97	      body: body || undefined,
98	      userId: activeUserId,
99	      queuedAt: Date.now(),
100	    };
101	    queue.push(record);
102	    return record.id;
103	  }
104	
105	  async function mutationWithOfflineQueue(req: Request, fetchImpl: typeof fetch): Promise<Response> {
106	    try {
107	      return await fetchImpl(req);
108	    } catch {
109	      const queueId = await enqueueOperation(req);
110	      return new Response(
111	        JSON.stringify({
112	          queued: true,
113	          queueId,
114	          message: 'You are offline. This operation will be submitted automatically when connectivity is restored.',
115	        }),
116	        {
117	          status: 202,
118	          headers: {
119	            'Content-Type': 'application/json',
120	            'X-Offline-Queued': 'true',
121	          },
122	        },
123	      );
124	    }
125	  }
126	
127	  async function replayQueue(
128	    fetchImpl: typeof fetch,
129	  ): Promise<Array<{ id: number; status?: number; success: boolean; error?: string }>> {
130	    const userOps = queue.filter((op) => !activeUserId || op.userId === activeUserId);
131	    const results = [];
132	    for (const op of userOps) {
133	      try {
134	        const init: RequestInit = { method: op.method, headers: op.headers };
135	        if (op.body && op.method !== 'GET' && op.method !== 'HEAD') init.body = op.body;
136	        const response = await fetchImpl(new Request(op.url, init));
137	        if (response.status < 500) {
138	          const idx = queue.findIndex((o) => o.id === op.id);
139	          if (idx !== -1) queue.splice(idx, 1);
140	        }
141	        results.push({ id: op.id, status: response.status, success: response.ok });
142	      } catch {
143	        results.push({ id: op.id, success: false, error: 'network' });
144	      }
145	    }
146	    return results;
147	  }
148	
149	  async function clearAllCaches() {
150	    const keys = await cacheApi.keys();
151	    await Promise.all(keys.map((k) => cacheApi.delete(k)));
152	    activeUserId = null;
153	  }
154	
155	  function setUser(userId: string) { activeUserId = userId; }
156	  function getUser() { return activeUserId; }
157	  function getQueue() { return [...queue]; }
158	  function getCaches() { return storedCaches; }
159	
160	  return {
161	    networkFirst,
162	    mutationWithOfflineQueue,
163	    replayQueue,
164	    clearAllCaches,
165	    setUser,
166	    getUser,
167	    getQueue,
168	    getCaches,
169	    userKbCacheName,
170	    userOpCacheName,
171	  };
172	}
