import { NotificationType } from '../common/enums/notification-type.enum';

const THROTTLE_LIMIT = 20;
const THROTTLE_WINDOW_MS = 60 * 60 * 1000; // 1 hour

export interface NotificationReference {
  type: string;
  id: string;
}

@Injectable()
