        Math.abs(amount),
        referenceType ?? null,
        referenceId ?? null,
        description ?? null,
        createdBy ?? null,
      );
    });
  }

  async recordEscrowHold(
    supplierId: string,
    amount: number,
    poId: string,
    createdBy?: string,
  ): Promise<void> {
    await this.dataSource.transaction(async (manager) => {
      await this.createEntry(
        manager,
        supplierId,
        LedgerEntryType.ESCROW_HOLD,
        -Math.abs(amount),
        'PURCHASE_ORDER',
        poId,
        `Escrow hold for PO`,
        createdBy ?? null,
      );
    });
  }

  async releaseEscrow(
    supplierId: string,
    amount: number,
    poId: string,
    createdBy?: string,
  ): Promise<void> {
    await this.dataSource.transaction(async (manager) => {
      await this.createEntry(
        manager,
        supplierId,
        LedgerEntryType.ESCROW_RELEASE,
        Math.abs(amount),
        'PURCHASE_ORDER',
        poId,
        `Escrow release for PO`,
        createdBy ?? null,
      );
    });
  }

  async recordPayment(
    supplierId: string,
    amount: number,
    poId: string,
    createdBy?: string,
  ): Promise<void> {
    await this.dataSource.transaction(async (manager) => {
      await this.createEntry(
        manager,
        supplierId,
        LedgerEntryType.PAYMENT,
        -Math.abs(amount),
        'PURCHASE_ORDER',
        poId,
        `Payment for PO`,
        createdBy ?? null,
      );
    });
  }

  async recordRefund(
    supplierId: string,
    amount: number,
    raId: string,
    createdBy?: string,
  ): Promise<void> {
    if (!supplierId) return; // no-op if supplier unknown
    await this.dataSource.transaction(async (manager) => {
      await this.createEntry(
        manager,
        supplierId,
        LedgerEntryType.REFUND,
        Math.abs(amount),
        'RETURN_AUTHORIZATION',
        raId,
        `Refund for return authorization`,
        createdBy ?? null,
      );
    });
  }

  async recordAdjustment(
    supplierId: string,
    amount: number,
    description: string,
    referenceType?: string,
    referenceId?: string,
    createdBy?: string,
  ): Promise<void> {
    await this.dataSource.transaction(async (manager) => {
      await this.createEntry(
        manager,
        supplierId,
        LedgerEntryType.ADJUSTMENT,
        amount,
        referenceType ?? null,
        referenceId ?? null,
        description,
        createdBy ?? null,
      );
    });
  }

  // ── Query methods ─────────────────────────────────────────────────────────

  async getLedger(supplierId: string, query: QueryLedgerDto) {
    const page = parseInt(query.page || '1', 10);
    const limit = Math.min(parseInt(query.limit || '20', 10), 100);
    const skip = (page - 1) * limit;

    const qb = this.entryRepo
      .createQueryBuilder('e')
      .leftJoinAndSelect('e.creator', 'creator')
      .where('e.supplierId = :supplierId', { supplierId })
      .orderBy('e.createdAt', 'DESC')
      .skip(skip)
      .take(limit);

    if (query.dateFrom) {
      qb.andWhere('e.createdAt >= :from', { from: new Date(query.dateFrom) });
    }
    if (query.dateTo) {
      qb.andWhere('e.createdAt <= :to', { to: new Date(query.dateTo) });
    }

    const [data, total] = await qb.getManyAndCount();
    return { data, meta: { page, limit, total, totalPages: Math.ceil(total / limit) } };
  }

  async getLedgerSummary(supplierId: string) {
    const result = await this.entryRepo
      .createQueryBuilder('e')
      .select('e.type', 'type')
      .addSelect('SUM(e.amount)', 'total')
      .where('e.supplierId = :supplierId', { supplierId })
      .groupBy('e.type')
      .getRawMany<{ type: string; total: string }>();

    const byType = Object.fromEntries(result.map((r) => [r.type, Number(r.total)]));

    const totalDeposits = byType['DEPOSIT'] ?? 0;
    const totalPayments = Math.abs(byType['PAYMENT'] ?? 0);
    const totalEscrowHolds = Math.abs(byType['ESCROW_HOLD'] ?? 0);
    const totalRefunds = byType['REFUND'] ?? 0;

    // Current balance = latest runningBalance
    const latest = await this.entryRepo.findOne({
      where: { supplierId },
      order: { createdAt: 'DESC' },
      select: ['runningBalance'],
    });
    const currentBalance = latest ? Number(latest.runningBalance) : 0;

    return {
      totalDeposits,
      totalPayments,
      totalEscrowHolds,
      totalRefunds,
      currentBalance,
    };
  }
}
