1	import { Navigate, useLocation } from 'react-router-dom';
2	import { useAuth } from '../contexts/AuthContext';
3	import { CHANGE_PASSWORD_PATH } from '../utils/routes';
4	
5	interface ProtectedRouteProps {
6	  children: React.ReactNode;
7	  roles?: string[];
8	}
9	
10	export function ProtectedRoute({ children, roles }: ProtectedRouteProps) {
11	  const { user, loading } = useAuth();
12	  const location = useLocation();
13	
14	  if (loading) {
15	    return <div className="loading">Loading...</div>;
16	  }
17	
18	  if (!user) {
19	    return <Navigate to="/login" replace />;
20	  }
21	
22	  // Force password change before accessing any other protected route.
23	  // The check is skipped when already on /change-password to prevent a redirect loop.
24	  if (user.mustChangePassword && location.pathname !== CHANGE_PASSWORD_PATH) {
25	    return <Navigate to="/change-password" replace />;
26	  }
27	
28	  if (roles && !roles.includes(user.role)) {
29	    return <Navigate to="/unauthorized" replace />;
30	  }
31	
32	  return <>{children}</>;
33	}
